// Get the incoming data from the webhook
const data = $input.first().json;

// Parse the body if it's a string
let snsData = data;
if (typeof data.body === 'string') {
  try {
    snsData = JSON.parse(data.body);
  } catch (error) {
    // If parsing fails, use the raw data
  }
}

// Handle subscription confirmation
if (snsData.Type === 'SubscriptionConfirmation') {
  return [{
    json: {
      messageType: 'SubscriptionConfirmation',
      subscribeURL: snsData.SubscribeURL,
      request: {
        method: 'GET',
        url: snsData.SubscribeURL
      }
    }
  }];
}

// Process the actual notification (alert)
if (snsData.Type === 'Notification') {
  // Parse the Message field which contains the actual finding
  let finding = snsData.Message;
  if (typeof finding === 'string') {
    try {
      finding = JSON.parse(finding);
    } catch (error) {
      // If it's not JSON, use it as is
    }
  }

  // Initialize variables
  let resourceId = null;
  let resourceType = null;
  let resourceArn = null;
  let accountId = null;
  let severity = null;
  let alertType = null;
  let alertDescription = null;
  let region = 'us-east-1';
  let findingSource = 'Unknown';
  let iamUserName = null;
  let roleName = null;
  let functionName = null;
  let accessKeyId = null;
  let sessionId = null;
  let additionalDetails = {};

  // --- Parse GuardDuty Finding ---
  if (finding.detail && finding.detail.resource) {
    findingSource = 'GuardDuty';
    const resource = finding.detail.resource;
    accountId = finding.account;
    severity = finding.detail.severity;
    alertType = finding.detail.type;
    alertDescription = finding.detail.description || '';
    region = finding.region || 'us-east-1';

    // EC2 Instance
    if (resource.instanceDetails) {
      resourceType = 'ec2-instance';
      resourceId = resource.instanceDetails.instanceId;
      resourceArn = resource.instanceDetails.instanceArn;
      additionalDetails = {
        instanceType: resource.instanceDetails.instanceType,
        privateIp: resource.instanceDetails.privateIpAddress,
        publicIp: resource.instanceDetails.publicIp
      };
    }
    // S3 Bucket
    else if (resource.s3BucketDetails) {
      resourceType = 's3-bucket';
      resourceId = resource.s3BucketDetails[0].bucketName;
      resourceArn = 'arn:aws:s3:::' + resourceId;
    }
    // RDS Instance
    else if (resource.rdsDbInstanceDetails) {
      resourceType = 'rds-instance';
      resourceId = resource.rdsDbInstanceDetails.dbInstanceIdentifier;
      resourceArn = resource.rdsDbInstanceDetails.dbInstanceArn;
    }
    // IAM Role (GuardDuty can detect compromised roles)
    else if (resource.roleDetails) {
      resourceType = 'iam-role';
      roleName = resource.roleDetails.roleName;
      resourceId = roleName;
      resourceArn = resource.roleDetails.arn;
    }
    // IAM User
    else if (resource.userDetails) {
      resourceType = 'iam-user';
      iamUserName = resource.userDetails.userName;
      resourceId = iamUserName;
      resourceArn = resource.userDetails.arn;
    }
    // Lambda Function
    else if (resource.lambdaFunctionDetails) {
      resourceType = 'lambda-function';
      functionName = resource.lambdaFunctionDetails.functionName;
      resourceId = functionName;
      resourceArn = resource.lambdaFunctionDetails.functionArn;
      region = resource.lambdaFunctionDetails.functionRegion || region;
    }
    // Access Key (IAM User credentials)
    else if (resource.accessKeyDetails) {
      resourceType = 'access-key';
      accessKeyId = resource.accessKeyDetails.accessKeyId;
      resourceId = accessKeyId;
      iamUserName = resource.accessKeyDetails.userName;
      resourceArn = resource.accessKeyDetails.arn;
    }
  }

  // --- Parse Security Hub Finding ---
  else if (finding.Resources && finding.Resources.length > 0) {
    findingSource = 'SecurityHub';
    accountId = finding.AwsAccountId;
    severity = finding.Severity && finding.Severity.Normalized;
    alertType = finding.Title;
    alertDescription = finding.Description || '';
    region = finding.Region || 'us-east-1';

    for (let i = 0; i < finding.Resources.length; i++) {
      const res = finding.Resources[i];
      if (res.Type === 'AwsEc2Instance') {
        resourceType = 'ec2-instance';
        resourceId = res.Id;
        resourceArn = res.Arn;
      } else if (res.Type === 'AwsS3Bucket') {
        resourceType = 's3-bucket';
        resourceId = res.Id;
        resourceArn = 'arn:aws:s3:::' + res.Id;
      } else if (res.Type === 'AwsIamUser') {
        resourceType = 'iam-user';
        iamUserName = res.Id;
        resourceId = iamUserName;
        resourceArn = res.Arn;
      } else if (res.Type === 'AwsIamRole') {
        resourceType = 'iam-role';
        roleName = res.Id;
        resourceId = roleName;
        resourceArn = res.Arn;
      } else if (res.Type === 'AwsRdsDbInstance') {
        resourceType = 'rds-instance';
        resourceId = res.Id;
        resourceArn = res.Arn;
      } else if (res.Type === 'AwsLambdaFunction') {
        resourceType = 'lambda-function';
        functionName = res.Id;
        resourceId = functionName;
        resourceArn = res.Arn;
      }
    }
  }

  // --- Parse AWS Config Compliance Change ---
  else if (finding.configurationItem) {
    findingSource = 'Config';
    const config = finding.configurationItem;
    resourceType = config.resourceType ? config.resourceType.toLowerCase().replace('aws::', '') : null;
    resourceId = config.resourceId;
    resourceArn = config.arn;
    accountId = config.awsAccountId;
    alertType = 'Config Compliance Change';
    alertDescription = 'Resource ' + resourceId + ' is non-compliant';
    region = config.awsRegion || 'us-east-1';

    // Map Config resource types to our standard types
    if (resourceType === 'ec2::instance') {
      resourceType = 'ec2-instance';
    } else if (resourceType === 's3::bucket') {
      resourceType = 's3-bucket';
    } else if (resourceType === 'iam::user') {
      resourceType = 'iam-user';
    } else if (resourceType === 'iam::role') {
      resourceType = 'iam-role';
    } else if (resourceType === 'lambda::function') {
      resourceType = 'lambda-function';
    } else if (resourceType === 'iam::accesskey') {
      resourceType = 'access-key';
    }
  }

  // --- Parse STS Temporary Credential Events ---
  // Check for STS-related findings in the alert
  if (finding.detail && finding.detail.sessionIssuer) {
    const session = finding.detail.sessionIssuer;
    if (session.userName && session.userType) {
      resourceType = 'sts-session';
      iamUserName = session.userName;
      resourceId = session.sessionId || session.userName;
      resourceArn = session.arn;
      sessionId = session.sessionId;
      additionalDetails.sessionDetails = {
        sessionId: sessionId,
        principalId: session.principalId,
        type: session.userType
      };
    }
  }

  // Check for temporary credentials in the finding
  if (finding.detail && finding.detail.awsCredentials) {
    const creds = finding.detail.awsCredentials;
    accessKeyId = creds.accessKeyId;
    additionalDetails.credentials = {
      accessKeyId: accessKeyId,
      expiration: creds.expiration,
      sessionToken: creds.sessionToken ? '[REDACTED]' : null
    };
    // If this is an STS session, mark it
    if (resourceType === 'sts-session' || !resourceType) {
      resourceType = 'sts-temp-credentials';
    }
  }

  // Determine if containment is needed based on severity and type
  let needsContainment = false;
  let containmentReason = '';

  if (severity) {
    if (severity >= 7) { // GuardDuty
      needsContainment = true;
      containmentReason = 'High severity alert (GuardDuty severity: ' + severity + ')';
    } else if (severity >= 70) { // Security Hub
      needsContainment = true;
      containmentReason = 'High severity alert (Security Hub severity: ' + severity + ')';
    }
  }

  // If no severity but we have a finding, still contain if it's a critical alert type
  if (!needsContainment && alertType) {
    const criticalTypes = ['UnauthorizedAccess', 'Compromised', 'Malicious', 'Breach', 'Attack', 'Anomaly', 'Suspicious'];
    for (let i = 0; i < criticalTypes.length; i++) {
      if (alertType.indexOf(criticalTypes[i]) !== -1) {
        needsContainment = true;
        containmentReason = 'Critical alert type: ' + alertType;
        break;
      }
    }
  }

  // Prepare output for the workflow
  return [{
    json: {
      messageType: 'Notification',
      resourceType: resourceType,
      resourceId: resourceId,
      resourceArn: resourceArn,
      accountId: accountId,
      severity: severity,
      needsContainment: needsContainment,
      containmentReason: containmentReason,
      alertType: alertType,
      alertDescription: alertDescription,
      region: region,
      findingSource: findingSource,
      iamUserName: iamUserName,
      roleName: roleName,
      functionName: functionName,
      accessKeyId: accessKeyId,
      sessionId: sessionId,
      additionalDetails: additionalDetails,
      finding: finding,
      originalMessage: snsData.Message,
      alertSummary: '[ALERT] ' + findingSource + ' - ' + alertType + ' on ' + resourceType + ' (' + resourceId + ')'
    }
  }];
}

// Fallback for unknown message types
return [{
  json: {
    messageType: 'Unknown',
    data: snsData
  }
}];

// Get the incoming data from the AWS Lambda node
const data = $input.first().json;

// ============================================
// STEP 1: Extract Lambda Response
// ============================================
const lambdaResponse = data.response || data.body || data;

// Determine if Lambda execution was successful
let executionStatus = 'success';
let errorMessage = null;
let containmentDetails = {};

// Check for errors in Lambda response
if (lambdaResponse.errorMessage || lambdaResponse.error) {
  executionStatus = 'failed';
  errorMessage = lambdaResponse.errorMessage || lambdaResponse.error || 'Unknown error';
} else if (lambdaResponse.statusCode && lambdaResponse.statusCode >= 400) {
  executionStatus = 'failed';
  errorMessage = 'Lambda returned status code: ' + lambdaResponse.statusCode;
} else if (lambdaResponse.status && lambdaResponse.status === 'failed') {
  executionStatus = 'failed';
  errorMessage = lambdaResponse.reason || 'Lambda execution failed';
}

// ============================================
// STEP 2: Parse Lambda Response Body (if JSON)
// ============================================
let parsedResponse = lambdaResponse;
if (typeof lambdaResponse.body === 'string') {
  try {
    parsedResponse = JSON.parse(lambdaResponse.body);
  } catch (error) {
    // If response body is not JSON, keep it as string
    parsedResponse = { message: lambdaResponse.body };
  }
}

// Extract containment details from the response
if (parsedResponse.status === 'success' || parsedResponse.status === 'contained') {
  containmentDetails = {
    action: parsedResponse.action || 'contained',
    resourceId: parsedResponse.resourceId || data.resourceId,
    resourceType: parsedResponse.resourceType || data.resourceType,
    details: parsedResponse.details || [],
    timestamp: parsedResponse.timestamp || new Date().toISOString()
  };
} else if (parsedResponse.details) {
  containmentDetails = {
    action: parsedResponse.action || 'contained',
    details: parsedResponse.details,
    timestamp: parsedResponse.timestamp || new Date().toISOString()
  };
}

// ============================================
// STEP 3: Determine Next Actions
// ============================================
let needsManualIntervention = false;
let manualInterventionReason = '';

// Check if Lambda indicates manual intervention needed
if (parsedResponse.requiresManualIntervention || parsedResponse.manualIntervention) {
  needsManualIntervention = true;
  manualInterventionReason = parsedResponse.manualInterventionReason || 'Lambda indicates manual intervention required';
}

// Check for specific resource types that might need additional actions
if (data.resourceType === 'ec2-instance' && executionStatus === 'success') {
  // EC2 containment might need additional verification
  if (!parsedResponse.quarantineGroupApplied) {
    needsManualIntervention = true;
    manualInterventionReason = 'EC2 quarantine group may not have been applied';
  }
}

if (data.resourceType === 's3-bucket' && executionStatus === 'success') {
  // S3 containment might need additional verification
  if (!parsedResponse.publicAccessBlocked) {
    needsManualIntervention = true;
    manualInterventionReason = 'S3 public access may not have been blocked';
  }
}

// ============================================
// STEP 4: Build Human-Readable Summary
// ============================================
let summary = '';
if (executionStatus === 'success') {
  summary = '✅ ' + data.resourceType + ' contained successfully';
  if (containmentDetails.details && containmentDetails.details.length > 0) {
    summary += ' - ' + containmentDetails.details.join(', ');
  }
} else {
  summary = '❌ Failed to contain ' + data.resourceType + ': ' + errorMessage;
  if (needsManualIntervention) {
    summary += ' ⚠️ Manual intervention required!';
  }
}

// ============================================
// STEP 5: Build Slack Message Fields
// ============================================
const slackMessage = {
  status: executionStatus,
  summary: summary,
  resourceType: data.resourceType,
  resourceId: data.resourceId,
  sirtID: data.sirtID || 'SIR-UNKNOWN',
  functionName: data.functionName || 'unknown',
  severity: data.severity || 'N/A',
  alertType: data.alertType || 'Unknown',
  accountId: data.accountId || 'N/A',
  region: data.region || 'us-east-1',
  containmentDetails: containmentDetails,
  needsManualIntervention: needsManualIntervention,
  manualInterventionReason: manualInterventionReason,
  errorMessage: errorMessage,
  timestamp: new Date().toISOString(),
  // Raw data for debugging
  lambdaResponse: lambdaResponse,
  parsedResponse: parsedResponse
};

// ============================================
// STEP 6: Build Slack Notification Text
// ============================================
let slackText = '🚨 **AWS Security - Lambda Containment Result**\n\n';
slackText += '*SIR ID:* `' + slackMessage.sirtID + '`\n';
slackText += '*Status:* ' + (executionStatus === 'success' ? '✅ Success' : '❌ Failed') + '\n';
slackText += '*Summary:* ' + summary + '\n\n';

slackText += '*Resource Details:*\n';
slackText += '• Type: ' + slackMessage.resourceType + '\n';
slackText += '• ID: `' + slackMessage.resourceId + '`\n';
slackText += '• Account: ' + slackMessage.accountId + '\n';
slackText += '• Region: ' + slackMessage.region + '\n';
slackText += '• Severity: ' + slackMessage.severity + '\n';
slackText += '• Alert: ' + slackMessage.alertType + '\n\n';

slackText += '*Lambda Details:*\n';
slackText += '• Function: `' + slackMessage.functionName + '`\n';
slackText += '• Timestamp: ' + slackMessage.timestamp + '\n\n';

if (containmentDetails.details && containmentDetails.details.length > 0) {
  slackText += '*Containment Actions:*\n';
  for (let i = 0; i < containmentDetails.details.length; i++) {
    slackText += '• ' + containmentDetails.details[i] + '\n';
  }
  slackText += '\n';
}

if (needsManualIntervention) {
  slackText += '⚠️ **Manual Intervention Required!**\n';
  slackText += '*Reason:* ' + manualInterventionReason + '\n\n';
}

if (errorMessage) {
  slackText += '*Error:* ' + errorMessage + '\n\n';
}

slackText += '🔗 *Containment completed* - Please verify resource is contained.';

// ============================================
// STEP 7: Prepare Output
// ============================================
return [{
  json: {
    // Original data
    resourceType: data.resourceType,
    resourceId: data.resourceId,
    accountId: data.accountId,
    region: data.region,
    severity: data.severity,
    alertType: data.alertType,
    alertDescription: data.alertDescription,
    sirtID: data.sirtID || 'SIR-UNKNOWN',
    functionName: data.functionName,

    // Lambda execution results
    executionStatus: executionStatus,
    errorMessage: errorMessage,
    lambdaResponse: lambdaResponse,
    parsedResponse: parsedResponse,

    // Containment details
    containmentDetails: containmentDetails,
    needsManualIntervention: needsManualIntervention,
    manualInterventionReason: manualInterventionReason,

    // Slack message
    slackText: slackText,
    slackMessage: slackMessage,

    // Summary for logging
    summary: summary,
    timestamp: new Date().toISOString()
  }
}];

// Get the incoming data from the previous node
const data = $input.first().json;

// ============================================
// STEP 1: Build Comprehensive Log Entry
// ============================================
const logEntry = {
  // Workflow metadata
  workflowName: 'aws-security-containment',
  workflowVersion: '1.0.0',
  timestamp: new Date().toISOString(),
  executionId: data.executionId || 'unknown',

  // Alert details
  sirtID: data.sirtID || 'SIR-UNKNOWN',
  alertType: data.alertType || 'Unknown',
  alertDescription: data.alertDescription || '',
  alertSource: data.findingSource || 'GuardDuty',
  severity: data.severity || 0,

  // Resource details
  resourceType: data.resourceType || 'unknown',
  resourceId: data.resourceId || 'unknown',
  resourceArn: data.resourceArn || '',
  accountId: data.accountId || 'unknown',
  region: data.region || 'us-east-1',

  // Lambda execution
  lambdaFunction: data.functionName || 'unknown',
  lambdaPayload: data.lambdaPayload || {},
  lambdaResponse: data.lambdaResponse || {},
  lambdaParsedResponse: data.parsedResponse || {},

  // Containment details
  containmentStatus: data.executionStatus || 'unknown',
  containmentActions: data.containmentDetails?.details || [],
  needsManualIntervention: data.needsManualIntervention || false,
  manualInterventionReason: data.manualInterventionReason || '',

  // Error handling
  errorMessage: data.errorMessage || null,

  // Summary
  summary: data.summary || 'No summary available',

  // Additional metadata
  slackText: data.slackText || '',
  tags: ['security', 'containment', 'automated-response']
};

// ============================================
// STEP 2: Build CloudWatch Log Formats
// ============================================

// 2a: JSON Log (structured for CloudWatch)
const jsonLog = JSON.stringify(logEntry);

// 2b: Human-Readable Log (for CloudWatch console)
let humanReadableLog = '========================================\n';
humanReadableLog += 'AWS SECURITY - CONTAINMENT LOG\n';
humanReadableLog += '========================================\n\n';
humanReadableLog += 'Timestamp: ' + logEntry.timestamp + '\n';
humanReadableLog += 'SIR ID: ' + logEntry.sirtID + '\n';
humanReadableLog += 'Execution ID: ' + logEntry.executionId + '\n\n';

humanReadableLog += '--- ALERT DETAILS ---\n';
humanReadableLog += 'Type: ' + logEntry.alertType + '\n';
humanReadableLog += 'Source: ' + logEntry.alertSource + '\n';
humanReadableLog += 'Severity: ' + logEntry.severity + '\n';
humanReadableLog += 'Description: ' + logEntry.alertDescription + '\n\n';

humanReadableLog += '--- RESOURCE DETAILS ---\n';
humanReadableLog += 'Type: ' + logEntry.resourceType + '\n';
humanReadableLog += 'ID: ' + logEntry.resourceId + '\n';
humanReadableLog += 'Account: ' + logEntry.accountId + '\n';
humanReadableLog += 'Region: ' + logEntry.region + '\n\n';

humanReadableLog += '--- CONTAINMENT ---\n';
humanReadableLog += 'Status: ' + logEntry.containmentStatus + '\n';
humanReadableLog += 'Lambda: ' + logEntry.lambdaFunction + '\n';
if (logEntry.containmentActions.length > 0) {
  humanReadableLog += 'Actions:\n';
  for (let i = 0; i < logEntry.containmentActions.length; i++) {
    humanReadableLog += '  - ' + logEntry.containmentActions[i] + '\n';
  }
}
humanReadableLog += '\n';

if (logEntry.needsManualIntervention) {
  humanReadableLog += '⚠️ MANUAL INTERVENTION REQUIRED!\n';
  humanReadableLog += 'Reason: ' + logEntry.manualInterventionReason + '\n\n';
}

if (logEntry.errorMessage) {
  humanReadableLog += '❌ ERROR:\n';
  humanReadableLog += logEntry.errorMessage + '\n\n';
}

humanReadableLog += 'Summary: ' + logEntry.summary + '\n';
humanReadableLog += '========================================\n';

// ============================================
// STEP 3: Prepare CloudWatch Log Events
// ============================================
const timestamp = Date.now();

// 3a: Single log event (JSON)
const cloudwatchJsonEvent = {
  logGroupName: '/aws/security/containment',
  logStreamName: logEntry.region + '/' + logEntry.accountId,
  logEvents: [{
    timestamp: timestamp,
    message: jsonLog
  }]
};

// 3b: Multiple log events (JSON + Human-readable)
const cloudwatchEvents = {
  logGroupName: '/aws/security/containment',
  logStreamName: logEntry.region + '/' + logEntry.accountId,
  logEvents: [
    {
      timestamp: timestamp,
      message: jsonLog
    },
    {
      timestamp: timestamp + 1,
      message: humanReadableLog
    }
  ]
};

// 3c: With severity-based filtering (for CloudWatch Insights)
const cloudwatchStructuredLog = {
  logGroupName: '/aws/security/containment',
  logStreamName: logEntry.region + '/' + logEntry.accountId,
  logEvents: [{
    timestamp: timestamp,
    message: JSON.stringify({
      ...logEntry,
      // Add severity level for CloudWatch Logs Insights
      logLevel: logEntry.severity >= 7 ? 'HIGH' : 
                logEntry.severity >= 4 ? 'MEDIUM' : 'LOW',
      status: logEntry.containmentStatus,
      // Add for easier querying
      '@timestamp': logEntry.timestamp,
      '@message': jsonLog
    })
  }]
};

// ============================================
// STEP 4: Return Data for CloudWatch Upload
// ============================================
return [{
  json: {
    // Original data
    ...data,

    // Log entries
    logEntry: logEntry,
    jsonLog: jsonLog,
    humanReadableLog: humanReadableLog,

    // CloudWatch configurations
    cloudwatch: {
      logGroupName: '/aws/security/containment',
      logStreamName: logEntry.region + '/' + logEntry.accountId,
      region: logEntry.region,
      accountId: logEntry.accountId
    },

    // CloudWatch log events (choose one)
    cloudwatchJsonEvent: cloudwatchJsonEvent,
    cloudwatchEvents: cloudwatchEvents,
    cloudwatchStructuredLog: cloudwatchStructuredLog,

    // For individual log event (AWS CloudWatch Logs node)
    logGroupName: '/aws/security/containment',
    logStreamName: logEntry.region + '/' + logEntry.accountId,
    logEvent: {
      timestamp: timestamp,
      message: jsonLog
    },

    // Status
    logged: true,
    logTimestamp: logEntry.timestamp,
    logSummary: 'Logged containment for ' + logEntry.sirtID + ' (' + logEntry.resourceId + ')'
  }
}];

// Get the incoming data from the previous node
const data = $input.first().json;

// ============================================
// STEP 1: Build Comprehensive Log Entry
// ============================================
const logEntry = {
  // Workflow metadata
  workflowName: 'aws-security-containment',
  workflowVersion: '1.0.0',
  timestamp: new Date().toISOString(),
  executionId: data.executionId || 'unknown',

  // Alert details
  sirtID: data.sirtID || 'SIR-UNKNOWN',
  alertType: data.alertType || 'Unknown',
  alertDescription: data.alertDescription || '',
  alertSource: data.findingSource || 'GuardDuty',
  severity: data.severity || 0,

  // Resource details
  resourceType: data.resourceType || 'unknown',
  resourceId: data.resourceId || 'unknown',
  resourceArn: data.resourceArn || '',
  accountId: data.accountId || 'unknown',
  region: data.region || 'us-east-1',

  // Lambda execution
  lambdaFunction: data.functionName || 'unknown',
  lambdaPayload: data.lambdaPayload || {},
  lambdaResponse: data.lambdaResponse || {},
  lambdaParsedResponse: data.parsedResponse || {},

  // Containment details
  containmentStatus: data.executionStatus || 'unknown',
  containmentActions: data.containmentDetails?.details || [],
  needsManualIntervention: data.needsManualIntervention || false,
  manualInterventionReason: data.manualInterventionReason || '',

  // Error handling
  errorMessage: data.errorMessage || null,

  // Summary
  summary: data.summary || 'No summary available',

  // Additional metadata
  slackText: data.slackText || '',
  tags: ['security', 'containment', 'automated-response']
};

// ============================================
// STEP 2: Build Splunk Log Formats
// ============================================

// 2a: Single event (for Splunk HEC)
const splunkSingleEvent = {
  event: logEntry,
  sourcetype: 'aws-security-containment',
  index: 'security',
  source: 'n8n-workflow',
  host: 'aws-containment-automation'
};

// 2b: Multiple events (batch mode)
const splunkBatchEvents = {
  events: [
    {
      event: logEntry,
      sourcetype: 'aws-security-containment',
      index: 'security',
      source: 'n8n-workflow',
      host: 'aws-containment-automation'
    }
  ]
};

// 2c: Raw data format (for non-JSON endpoints)
const splunkRawEvent = {
  event: JSON.stringify(logEntry),
  sourcetype: 'json',
  index: 'security'
};

// 2d: With custom metadata (for Splunk search optimization)
const splunkEnhancedEvent = {
  event: {
    ...logEntry,
    // Add Splunk-optimized fields
    severity_level: logEntry.severity >= 7 ? 'critical' : 
                     logEntry.severity >= 4 ? 'high' : 'medium',
    resource_category: logEntry.resourceType,
    containment_required: logEntry.needsManualIntervention ? 'yes' : 'no',
    execution_time: new Date().toISOString()
  },
  sourcetype: 'aws-security-containment',
  index: 'security',
  source: 'n8n-workflow',
  host: 'aws-containment-automation'
};

// ============================================
// STEP 3: Build Splunk-Friendly Log Formats
// ============================================

// 3a: JSON for Splunk (structured)
const splunkJsonLog = JSON.stringify(logEntry);

// 3b: Human-readable for Splunk (for free text search)
let splunkHumanReadable = 'TIMESTAMP=' + logEntry.timestamp + ' ';
splunkHumanReadable += 'SIR_ID=' + logEntry.sirtID + ' ';
splunkHumanReadable += 'RESOURCE_TYPE=' + logEntry.resourceType + ' ';
splunkHumanReadable += 'RESOURCE_ID=' + logEntry.resourceId + ' ';
splunkHumanReadable += 'ACCOUNT=' + logEntry.accountId + ' ';
splunkHumanReadable += 'REGION=' + logEntry.region + ' ';
splunkHumanReadable += 'SEVERITY=' + logEntry.severity + ' ';
splunkHumanReadable += 'STATUS=' + logEntry.containmentStatus + ' ';
splunkHumanReadable += 'LAMBDA=' + logEntry.lambdaFunction + ' ';
if (logEntry.errorMessage) {
  splunkHumanReadable += 'ERROR=' + logEntry.errorMessage + ' ';
}
splunkHumanReadable += 'SUMMARY=' + logEntry.summary;

// 3c: Key-Value format (Splunk default)
let splunkKeyValue = '';
for (const [key, value] of Object.entries(logEntry)) {
  if (value !== null && value !== undefined) {
    if (typeof value === 'object') {
      splunkKeyValue += key + '=' + JSON.stringify(value) + ' ';
    } else {
      splunkKeyValue += key + '=' + value + ' ';
    }
  }
}

// ============================================
// STEP 4: Prepare Splunk HEC Configurations
// ============================================

// Splunk HEC configuration (for HTTP Request node)
const splunkConfig = {
  endpoint: 'https://your-splunk-instance:8088/services/collector',
  authHeader: 'Splunk YOUR_HEC_TOKEN', // Replace with your actual token
  headers: {
    'Authorization': 'Splunk YOUR_HEC_TOKEN',
    'Content-Type': 'application/json'
  },
  // Use one of the event formats above
  body: splunkSingleEvent
};

// ============================================
// STEP 5: Return Data for Splunk Upload
// ============================================
return [{
  json: {
    // Original data
    ...data,

    // Log entries
    logEntry: logEntry,
    splunkJsonLog: splunkJsonLog,
    splunkHumanReadable: splunkHumanReadable,
    splunkKeyValue: splunkKeyValue,

    // Splunk event formats
    splunkSingleEvent: splunkSingleEvent,
    splunkBatchEvents: splunkBatchEvents,
    splunkEnhancedEvent: splunkEnhancedEvent,

    // Splunk configuration
    splunkConfig: splunkConfig,
    splunkEndpoint: 'https://your-splunk-instance:8088/services/collector',
    splunkAuthHeader: 'Splunk YOUR_HEC_TOKEN',

    // For quick copy-paste
    splunkRawBody: JSON.stringify(splunkSingleEvent),

    // Status
    logged: true,
    logTimestamp: logEntry.timestamp,
    logSummary: 'Logged containment for ' + logEntry.sirtID + ' (' + logEntry.resourceId + ')'
  }
}];

// Get the incoming data
const data = $input.first().json;

// ============================================
// STEP 1: Extract SIR ID from GuardDuty Finding
// ============================================
let sirtID = 'SIR-UNKNOWN';

// Option 1: Use alert type as fallback
sirtID = data.alertType || 'SIR-UNKNOWN';

// Option 2: If there's a finding ID in the original data
if (data.finding && data.finding.detail && data.finding.detail.id) {
  sirtID = 'SIR-' + data.finding.detail.id.substring(0, 8);
}

// Option 3: Use GuardDuty finding ID with timestamp
if (data.finding && data.finding.detail && data.finding.detail.service) {
  const service = data.finding.detail.service;
  if (service.eventFirstSeen) {
    const year = new Date(service.eventFirstSeen).getFullYear();
    const id = data.finding.detail.id.substring(0, 6);
    sirtID = 'SIR-' + year + '-' + id;
  }
}

// Option 4: Use finding ID from Security Hub
if (data.finding && data.finding.Id) {
  sirtID = 'SIR-' + data.finding.Id.substring(0, 8);
}

// ============================================
// STEP 2: Map Resource Types to Lambda Functions
// ============================================
const lambdaConfigs = {
  'ec2-instance': {
    functionName: 'contain-ec2-instance',
    buildPayload: (data) => ({
      targetInstanceId: data.resourceId,
      targetAccount: data.accountId,
      targetRegion: data.region,
      sirtID: sirtID,  // Use the extracted SIR ID
      severity: data.severity,
      alertDescription: data.alertDescription,
      instanceDetails: data.additionalDetails || {}
    })
  },

  's3-bucket': {
    functionName: 'contain-s3-bucket',
    buildPayload: (data) => ({
      targetBucketName: data.resourceId,
      sirtID: sirtID,  // Use the extracted SIR ID
      targetAccount: data.accountId,
      targetRegion: data.region,
      severity: data.severity,
      alertDescription: data.alertDescription
    })
  },

  'iam-user': {
    functionName: 'contain-iam-user',
    buildPayload: (data) => ({
      targetUserName: data.resourceId,
      targetAccount: data.accountId,
      targetRegion: data.region,
      sirtID: sirtID,  // Use the extracted SIR ID
      severity: data.severity,
      accessKeyId: data.accessKeyId,
      alertDescription: data.alertDescription
    })
  },

  'iam-role': {
    functionName: 'contain-iam-role',
    buildPayload: (data) => ({
      targetRoleName: data.resourceId,
      targetAccount: data.accountId,
      targetRegion: data.region,
      sirtID: sirtID,  // Use the extracted SIR ID
      severity: data.severity,
      alertDescription: data.alertDescription
    })
  },

  'lambda-function': {
    functionName: 'contain-lambda-function',
    buildPayload: (data) => ({
      targetFunctionName: data.resourceId,
      targetAccount: data.accountId,
      targetRegion: data.region,
      sirtID: sirtID,  // Use the extracted SIR ID
      severity: data.severity,
      alertDescription: data.alertDescription
    })
  },

  'rds-instance': {
    functionName: 'contain-rds-instance',
    buildPayload: (data) => ({
      targetDBInstanceIdentifier: data.resourceId,
      targetAccount: data.accountId,
      targetRegion: data.region,
      sirtID: sirtID,  // Use the extracted SIR ID
      severity: data.severity,
      alertDescription: data.alertDescription
    })
  },

  'access-key': {
    functionName: 'contain-access-key',
    buildPayload: (data) => ({
      targetAccessKeyId: data.resourceId,
      targetUserName: data.iamUserName,
      targetAccount: data.accountId,
      targetRegion: data.region,
      sirtID: sirtID,  // Use the extracted SIR ID
      severity: data.severity,
      alertDescription: data.alertDescription
    })
  },

  'sts-session': {
    functionName: 'contain-sts-session',
    buildPayload: (data) => ({
      targetAccessKeyId: data.accessKeyId,
      targetUserName: data.iamUserName,
      targetSessionId: data.sessionId,
      targetAccount: data.accountId,
      targetRegion: data.region,
      sirtID: sirtID,  // Use the extracted SIR ID
      severity: data.severity,
      alertDescription: data.alertDescription
    })
  },

  'sts-temp-credentials': {
    functionName: 'contain-sts-session',
    buildPayload: (data) => ({
      targetAccessKeyId: data.accessKeyId,
      targetUserName: data.iamUserName,
      targetSessionId: data.sessionId,
      targetAccount: data.accountId,
      targetRegion: data.region,
      sirtID: sirtID,  // Use the extracted SIR ID
      severity: data.severity,
      alertDescription: data.alertDescription
    })
  }
};

// ============================================
// STEP 3: Build the Lambda Payload
// ============================================
const resourceType = data.resourceType;
const config = lambdaConfigs[resourceType];

// Default configuration for unknown resource types
let functionName = 'contain-unknown-resource';
let lambdaPayload = {
  targetResourceType: resourceType,
  targetResourceId: data.resourceId,
  targetAccount: data.accountId,
  targetRegion: data.region,
  sirtID: sirtID,  // Use the extracted SIR ID
  severity: data.severity,
  alertDescription: data.alertDescription
};

// If we have a configuration, use it
if (config) {
  functionName = config.functionName;
  lambdaPayload = config.buildPayload(data);
}

// ============================================
// STEP 4: Add Debug Info (Optional)
// ============================================
console.log('SIR ID:', sirtID);
console.log('Resource Type:', resourceType);
console.log('Lambda Function:', functionName);
console.log('Payload:', JSON.stringify(lambdaPayload));

// ============================================
// STEP 5: Return the Data
// ============================================
return [{
  json: {
    ...data,
    functionName: functionName,
    lambdaPayload: lambdaPayload,
    sirtID: sirtID,  // Make SIR ID available for later nodes
    lambdaSummary: 'Invoking ' + functionName + ' for ' + resourceType + ': ' + data.resourceId + ' (SIR: ' + sirtID + ')'
  }
}];
